"use client";
import React, { useState } from "react";
import { GoogleAuthProvider, signInWithPopup } from "firebase/auth";
import { useRouter } from "next/navigation";
import { auth } from "../lib/firebase";
import Link from "next/link";
const page = () => {
  const router = useRouter();
  const [FormData, setFormData] = useState({
    email: "",

    Username: "",
    password: "",
  });
  const [Error, setError] = useState("");
  const [Loading, setLoading] = useState(false);

  const handleChange = (e) => {
    setFormData({
      ...FormData,
      [e.target.name]: e.target.value,
    });
    if (Error) setError("");
  };

  const Validation = () => {
    const { email, password, Username } = FormData;

    const Emailregex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!email.trim()) {
      return "Email is required";
    }
    // 2. Check if Email format is wrong
    if (!Emailregex.test(email)) {
      return "Invalid email format";
    }

    if (!Username) {
      return "Username is required";
    }

    if (Username.length < 6) {
      return "Username must be at least 6 characters.";
    }
    // 3. If Email is fine, check Password
    if (!password) {
      return "Password is required";
    }
    // 4. Check Password length
    if (password.length < 6) {
      return "Password must be at least 6 characters";
    }

    return null;
  };
  const HandleSubmit = async (e) => {
    e.preventDefault();
    //validation checking
    const validation = Validation();
    if (validation) {
      setError(validation);
      return;
    }

    setError("");
    setLoading(true);
    //console.log("Success! Logging in with:", FormData);
    // Add your Firebase signUpWithEmailAndPassword here
    try {
      const signupusers = await createUse
    } catch (err) {
      setError(error.message);
    }
    setLoading(false);
    setFormData({
      email: "",
      Username: "",
      password: "",
    });
  };

  const HandleGoogleSignup = async () => {
    try {
      const provider = new GoogleAuthProvider();
      await signInWithPopup(auth, provider);
      // Redirect to home page
      router.push("/");
    } catch (error) {
      //console.error("Login Error:", error);
      setError("Something Went Wrong In Google Login. ");
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-gray-300 via-gray-100 to-gray-400 p-4">
      <div className="w-full max-w-md bg-white rounded-3xl shadow-2xl p-8 border border-blue-900">
        {Error && (
          <div className="mb-6 flex items-center p-2 text-sm text-red-800 border-l-4 border-red-600 bg-red-100 rounded-r-xl animate-in fade-in slide-in-from-top-4 duration-300">
            <span className="material-symbols-rounded mr-3 text-red-600">
              error
            </span>
            <div className="flex-1 font-medium">{Error}</div>
            <button
              onClick={() => setError("")}
              className="ml-auto bg-red-50 text-red-500 rounded-lg p-1 hover:bg-red-100 transition-colors"
            >
              <span className="material-symbols-rounded text-base">close</span>
            </button>
          </div>
        )}
        {/* Header */}
        <div className="text-left mb-2">
          <h1 className="text-3xl font-extrabold text-rose-950 mb-2 tracking-tight">
            Login
          </h1>
          <p className="text-gray-500 text-sm">
            Please sign in to your account
          </p>
        </div>
        <hr className="mb-6 text-rose-950" />

        <form className="space-y-4">
          {/* Email Field */}
          <div className="group">
            <label className="block text-sm font-bold text-blue-900 mb-1 ml-1">
              Email Address
            </label>
            <div className="relative">
              <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                <span className="material-symbols-rounded text-gray-400 group-focus-within:text-rose-950 transition-colors text-sm">
                  mail
                </span>
              </div>
              <input
                type="email"
                name="email"
                onChange={handleChange}
                value={FormData.email}
                className={`block w-full pl-12 pr-4 py-2 bg-gray-50 border ${Error.includes("email") || Error.includes("Email") ? "border-red-500 ring-1 ring-red-100" : "border-gray-500"} rounded-2xl text-gray-700 focus:outline-none focus:ring-2 focus:ring-rose-950 transition-all text-sm`}
                placeholder="name@company.com"
              />
            </div>
          </div>
          {/* Username Field */}
          <div className="group">
            <label className="block text-sm font-bold text-blue-900 mb-1 ml-1">
              Username
            </label>
            <div className="relative">
              <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                <span className="material-symbols-rounded text-gray-400 group-focus-within:text-rose-950 transition-colors text-sm">
                  mail
                </span>
              </div>
              <input
                type="text"
                name="Username"
                onChange={handleChange}
                value={FormData.Username}
                className={`block w-full pl-12 pr-4 py-2 bg-gray-50 border ${
                  Error.includes("Username")
                    ? "border-red-500 ring-1 ring-red-100"
                    : "border-gray-500"
                } rounded-2xl text-gray-700 focus:outline-none focus:ring-2 focus:ring-rose-950 transition-all text-sm`}
                placeholder="Username"
              />
            </div>
          </div>

          {/* Password Field */}
          <div className="group">
            <label className="block text-sm font-bold text-blue-900 mb-1 ml-1">
              Password
            </label>
            <div className="relative">
              <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                <span className="material-symbols-rounded text-gray-400 group-focus-within:text-rose-950 transition-colors text-sm">
                  lock
                </span>
              </div>
              <input
                type="password"
                name="password"
                value={FormData.password}
                onChange={handleChange}
                className={`block w-full pl-12 pr-4 py-2 bg-gray-50 border ${Error.includes("Password") ? "border-red-500 ring-1 ring-red-100" : "border-gray-500"} rounded-2xl text-gray-700 focus:outline-none focus:ring-2 focus:ring-rose-950 transition-all text-sm`}
                placeholder="••••••••"
              />
            </div>
          </div>

          {/* Actions */}
          <div className="flex items-center justify-between text-sm px-1 py-1">
            <label className="flex items-center text-gray-500 cursor-pointer hover:text-gray-700">
              <input
                type="checkbox"
                className="w-4 h-4 rounded border-gray-300 text-rose-950 focus:ring-rose-950 mr-2"
              />
              Remember me
            </label>
            <a
              href="#"
              className="font-semibold text-rose-950 hover:text-rose-800"
            >
              Forgot password?
            </a>
          </div>

          {/* Submit Buttons */}
          <div className="flex flex-row gap-3 pt-2">
            {/* Google Sign-In Button */}
            <button
              type="button"
              onClick={HandleGoogleSignup}
              className="w-full flex justify-center items-center py-2 px-4 rounded-2xl border border-gray-200 shadow-sm bg-blue-800 hover:bg-blue-900 active:scale-[0.98] transition-all font-bold text-sm text-gray-100"
            >
              <img
                src="https://www.gstatic.com/images/branding/product/1x/gsa_512dp.png"
                alt="Google"
                className="w-8 h-8 mr-2"
              />
              <span className="text-sm"> Google Login</span>
            </button>

            {/* Sign In Button */}
            <button
              type="submit"
              onClick={HandleSubmit}
              className="w-full flex justify-center items-center py-2 px-4 rounded-2xl shadow-lg shadow-rose-950/20 text-white bg-rose-950 hover:bg-rose-900 active:scale-[0.98] transition-all font-bold text-sm"
            >
              <span>Sign In</span>
              <span className="material-symbols-rounded ml-2">
                arrow_forward
              </span>
            </button>
          </div>
        </form>
        {/* Footer */}
        <div className="mt-6 pt-4 border-t border-gray-100 text-center">
          <p className="text-sm text-gray-500">
            New here?{" "}
            <Link
              href="/signup"
              className="font-bold text-rose-950 hover:underline underline-offset-4"
            >
              Create an account
            </Link>
          </p>
        </div>
      </div>
    </div>
  );
};

export default page;
